::: {.cell}

```{.r .cell-code}
column_headers <- c("bball_win_pct", "overall_fb_win_pct")

img_urls <- c(
  "https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png",
  "https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png"
)

add_header <- function(col_name, img_url) {
  gtExtras::img_header(
    label = "",
    img_url = img_url,
    height = 25,
    palette = c("white")
  )
}

col_headers_with_images <- purrr::map2(column_headers, img_urls, add_header) |>
  purrr::set_names(column_headers)


cup_tbl <- all_sports |>
  dplyr::filter(top_ten > 14.5) |>
  dplyr::arrange(-top_ten) |>
  cbbplotR::gt_cbb_teams(team, team) |>
  gt::gt() |>
  gtUtils::gt_theme_gtutils() |>
  gt::fmt_markdown(team) |>
  gt::cols_align(team, align = "left") |>
  gt::cols_label(team = "", !!!col_headers_with_images) |>
  gtUtils::gt_color_pills(
    bball_win_pct,
    domain = c(.3, .85),
    format_type = "percent",
    digits = 1,
    palette = c("#8B0000", "#FF0000", "#FF4500", "#ADFF2F", "#008000"),
  ) |>
  gtUtils::gt_color_pills(
    overall_fb_win_pct,
    domain = c(.3, .85),
    format_type = "percent",
    digits = 1,
    palette = c("#8B0000", "#FF0000", "#FF4500", "#ADFF2F", "#008000"),
  ) |>
  gt::cols_nanoplot(
    columns = all_fb_win_pct,
    reference_line = .5,
    autohide = TRUE,
    autoscale = TRUE,
    options = gt::nanoplot_options(
      data_area_fill_color = "lightpink",
      reference_line_color = "#333333",
      show_data_area = TRUE,
      data_line_type = "curved",
      show_data_points = FALSE
    )
  ) |>
  gt::cols_label(
    team = "",
    top_ten = "Top 10s",
     nanoplots = "Football Win %: 1993 to 2024"
  ) |> 
  gtExtras::gt_add_divider(columns = c(team, bball_win_pct),
                           sides = "right",
                           color = "black") |>
  gt::tab_header(title = gt::html("Win percentage in football and men's basketball since 1993-94 for public schools with most Top 10 Finishes in Directors' Cup<hr>")) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data from wikipedia.com, stathead.com, {cfbfastR}, and theme for {gtUtils}. Idea from Neil Paine.<br>The Directors' Cup is a competition between athletic departments that ranks schools based on performance across all men’s and women’s varsity sports<br>
                <hr><b>Table by Chris at Bless your chart | December 13, 2024</b>"
      )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(font = gt::google_font("Signika Negative"))),
    locations = gt::cells_body(columns = team)
  ) |>
  gt::tab_style(
    locations = gt::cells_column_labels(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(15)
    )
  ) |> 
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(10),
      weight = 250
    )
  ) |>
    gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(15)
    )
  ) |> 
  gtExtras::gt_highlight_rows(rows = c(2),
                              columns = c(1:4),
                              fill = "#FFFFC5") |>
  gt::tab_options(table.width = gt::px(725))


 gtUtils::gt_save_crop(
  cup_tbl,
  file = "cup_tbl.png",
  whitespace = 30,
  bg = "#FFFDF5"
 )

