### Add data for cfb conferences


::: {.cell}

```{.r .cell-code}
ffhome_games <- cfbfastR::cfbd_game_info(year = 2024) |>
  dplyr::filter(!is.na(home_points)) |>
  dplyr::mutate(result = dplyr::if_else(home_points > away_points, "W", "L")) |>
  dplyr::rename(
    team = home_team,
    opp = away_team,
    conf = home_conference,
    opp_conf = away_conference,
    team_points = home_points,
    opp_points = away_points
  ) |>
  dplyr::select(game_id, week, team, opp, conf, opp_conf, result)

# Away results
ffaway_games <- cfbfastR::cfbd_game_info(year = 2024) |>
  dplyr::filter(!is.na(home_points)) |>
  dplyr::mutate(result = dplyr::if_else(away_points > home_points, "W", "L")) |>
  dplyr::rename(
    team = away_team,
    opp = home_team,
    conf = away_conference,
    opp_conf = home_conference
  ) |>
  dplyr::select(game_id, week, team, opp, conf, opp_conf, result)

# First find total teams in each conference 
total_conf_teams <- ffhome_games |>
  dplyr::bind_rows(ffaway_games) |>
  dplyr::filter(conf %in% c("ACC", "SEC", "Big 12", "Big Ten")) |> 
  dplyr::group_by(conf) |>
  dplyr::summarise(
    total_teams = dplyr::n_distinct(team)
  ) |> 
  dplyr::mutate(
    conf_games = dplyr::if_else(conf == "Big Ten", 9, 8)
  )


# Now find non conference games 
fbs_conf <- c("Mountain West", "Big Ten", "ACC", "Mid-American",
              "Big 12", "Sun Belt", "SEC", "American Athletic", 
              "Conference USA", "Pac-12", "FBS Independents")

ffgames <- ffhome_games |>
  dplyr::bind_rows(ffaway_games) |>
  dplyr::filter(conf != opp_conf) |> 
  dplyr::mutate(
    fbs_conf = dplyr::if_else(opp_conf %in% fbs_conf, "FBS", "Non-FBS")
  ) 

sec_games <- ffgames |> 
  dplyr::filter(conf %in% c("SEC")) |> 
  dplyr::group_by(conf, opp_conf, fbs_conf) |> 
  dplyr::summarise(
    total_games = dplyr::n()  # Total number of games
  ) 
